UPDATE workflow_entity SET nodes = '[{"parameters":{"options":{},"public":false,"initialMessage":"你好！我是跨境电商业务助手。\n\n我可以帮你查询：\n- 亚马逊运营SOP规范\n- ERP发补货流程\n- 亚马逊政策红线\n- 选品分析方法论\n\n请直接提问，我会从公司知识库中检索最准确的答案。"},"id":"a0000001-e001-4000-a001-000000000001","name":"Chat Trigger","type":"@n8n/n8n-nodes-langchain.chatTrigger","typeVersion":1.1,"position":[240,304],"webhookId":"bd84a280-9629-4767-ba08-58ac743eb7f8"},{"parameters":{"promptType":"define","text":"你是一名资深的跨境电商运营专家和AI助手。你拥有以下核心能力：\n\n1. **亚马逊运营规范**：熟悉产品上架、Listing优化、广告投放、库存管理等全链路SOP\n2. **ERP发补货流程**：精通FBA补货策略、库存周转计算、供应链异常处理\n3. **亚马逊政策红线**：了解账号健康指标、知识产权政策、评论合规等关键红线\n4. **选品分析方法论**：掌握市场容量分析、竞品调研、利润测算等选品核心方法\n\n**重要规则：**\n- 当用户询问关于公司内部规范、SOP、政策或具体操作流程时，你必须使用 Vector Store Tool 检索公司知识库中的权威信息\n- 基于检索到的上下文给出精准回答，如果知识库中没有相关信息，请诚实告知\n- 回答时引用知识库中的具体数据或规定，保持专业、清晰、结构化的回答风格\n- 使用中文回复，适当使用分点或表格组织信息","options":{}},"id":"a0000002-e001-4000-a002-000000000002","name":"AI Agent","type":"@n8n/n8n-nodes-langchain.agent","typeVersion":3.1,"position":[704,304]},{"parameters":{"contextWindowLength":10,"sessionKey":"={{ $json.sessionId }}"},"id":"a0000003-e001-4000-a003-000000000003","name":"Window Buffer Memory","type":"@n8n/n8n-nodes-langchain.memoryBufferWindow","typeVersion":1.4,"position":[480,512]},{"parameters":{"description":"当需要查询公司内部的跨境电商SOP、ERP发补货规范、亚马逊政策红线或选品分析方法论时，必须调用此工具进行事实检索。该工具连接公司Obsidian知识库的向量数据库，包含所有内部业务文档的标准操作流程和决策规范。输入应为完整的检索问句。","topK":4},"id":"a0000005-e001-4000-a005-000000000005","name":"知识库检索工具","type":"@n8n/n8n-nodes-langchain.toolVectorStore","typeVersion":1.1,"position":[928,512]},{"parameters":{"memoryKey":{"mode":"list","value":"obsidian_knowledge_base"},"mode":"retrieve"},"id":"a0000006-e001-4000-a006-000000000006","name":"Vector Store","type":"@n8n/n8n-nodes-langchain.vectorStoreInMemory","typeVersion":1.2,"position":[1152,512]},{"parameters":{"model":"nomic-embed-text"},"id":"a0000008-e001-4000-a008-000000000008","name":"Embeddings Ollama","type":"@n8n/n8n-nodes-langchain.embeddingsOllama","typeVersion":1,"pos